import (
  "github.com/openmeterio/openmeter/openmeter/ent/db"
  "github.com/openmeterio/openmeter/openmeter/productcatalog/adapter"
)

repo := adapter.NewPostgresFeatureRepo(dbClient, logger) // returns feature.FeatureRepo

func (h *featureHandlers) GetFeature() GetFeatureHandler {
  return httptransport.NewHandlerWithArgs(
    func(ctx context.Context, r *http.Request, featureID string) (models.NamespacedID, error) {
      ns, err := h.resolveNamespace(ctx)
      if err != nil { return models.NamespacedID{}, err }
      return models.NamespacedID{Namespace: ns, ID: featureID}, nil
    },
    func(ctx context.Context, id models.NamespacedID) (api.Feature, error) {
      feat, err := h.connector.GetFeature(ctx, id.Namespace, id.ID, feature.IncludeArchivedFeatureFalse)
      if err != nil { return api.Feature{}, err }
      return MapFeatureToResponse(*feat)
    },
    commonhttp.JSONResponseEncoder,
    httptransport.AppendOptions(h.options, httptransport.WithErrorEncoder(getErrorEncoder()), httptransport.WithOperationName("getFeature"))...,
  )
}

// in featureConnector.CreateFeature
if _, err := ulid.Parse(feature.Key); err == nil {
  return Feature{}, models.NewGenericValidationError(fmt.Errorf("Feature key cannot be a valid ULID"))
}
createdFeature, err := c.featureRepo.CreateFeature(ctx, feature)
if err != nil { return Feature{}, err }
if err := c.publisher.Publish(ctx, NewFeatureCreateEvent(ctx, &createdFeature)); err != nil {
  return createdFeature, fmt.Errorf("failed to publish feature created event: %w", err)
}

resolver, _ := featureresolver.New(featureConnector)
if err := featureresolver.ResolveFeaturesForRateCards(ctx, resolver, namespace, rateCards); err != nil {
  return err // NillableGenericValidationError wrapping ErrRateCardFeatureNotFound/Mismatch
